INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Landline texting$q$, $q$Enables secure two-way SMS and RCS texting on a practice's existing office landline number, so no new number or app is required for patients.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Voice and video calling$q$, $q$Built-in voice and video calling lets staff handle appointments, follow-ups, and telehealth visits from the same inbox as text messages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Nia AI assistant$q$, $q$An AI voice and text assistant (available on the Automate plan) answers routine patient calls, handles common questions, and routes complex issues to staff.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Automated workflows$q$, $q$Configurable workflows send appointment reminders, intake forms, and recall messages automatically based on practice-defined triggers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Website chat widget$q$, $q$A chat widget can be embedded on a practice website so visitors can text the practice directly from a browser.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Call-to-text and voicemail transcription$q$, $q$Incoming calls can be converted into text conversations, and voicemails are automatically transcribed for faster staff review.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$EHR integration$q$, $q$Automate and Enterprise plans connect to electronic health record systems to sync patient data and reduce duplicate entry.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$HIPAA compliance and BAA$q$, $q$All plans include a signed Business Associate Agreement and multi-factor authentication to meet HIPAA security requirements for patient communication.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Patients can text a practice's existing landline number without installing an app$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$HIPAA compliance and a signed BAA are included on every plan$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Nia AI assistant can absorb routine call volume for busy front desks$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Combines texting, calling, chat, and team messaging in one inbox$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Purpose-built for healthcare workflows like intake, reminders, and recalls$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Pricing starts at $300/month, higher than many general-purpose business texting tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Automate plan's calling usage is billed separately on top of the base subscription$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$AI assistant (Nia) and EHR integration require the more expensive Automate tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Enterprise pricing is custom and not published, requiring a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Smaller company size (roughly 40-50 employees) than larger healthcare-communication rivals$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$What is OhMD used for?$q$, $q$OhMD is a HIPAA-compliant patient communication platform that lets healthcare practices text, call, and message patients from their existing office landline, reducing phone tag and call volume.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Is OhMD HIPAA compliant?$q$, $q$Yes. OhMD includes a signed Business Associate Agreement (BAA) and multi-factor authentication on every plan to meet HIPAA requirements for handling patient information.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$How much does OhMD cost?$q$, $q$OhMD's published plans start at $300/month for the Communicate plan and $500/month for the Automate plan, which adds the Nia AI assistant and EHR integration. Enterprise pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Do patients need to download an app to use OhMD?$q$, $q$No. OhMD lets patients text a practice's existing landline number using standard SMS or RCS messaging, so no app download is required on either side.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$What is Nia in OhMD?$q$, $q$Nia is OhMD's AI voice and text assistant, available on the Automate plan, which can answer routine patient calls, handle common scheduling questions, and route more complex calls to staff.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Does OhMD integrate with EHR systems?$q$, $q$Yes, EHR integration is available on the Automate and Enterprise plans to sync patient records and reduce duplicate data entry for front-desk staff.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Who founded OhMD?$q$, $q$OhMD was co-founded in 2015 by CEO Ethan Bechtel and is headquartered in Burlington, Vermont.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Reducing front-desk call volume$q$, $q$Practices deflect routine phone calls into text conversations and AI-handled calls, freeing front-desk staff to focus on in-person patients.$q$, $q$Small and mid-sized medical or dental practices$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Appointment reminders and recalls$q$, $q$Automated workflows text patients reminders, recall notices, and intake forms ahead of visits to reduce no-shows.$q$, $q$Practice administrators and office managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Telehealth and follow-up care$q$, $q$Voice and video calling combined with texting lets providers run telehealth visits and post-visit follow-ups from a single tool.$q$, $q$Physicians, physical therapists, and specialty clinics$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Communicate$q$, $q$$300/month$q$, $q$monthly$q$, NULL, $q$["Two-way SMS and RCS texting","Text-enabled landline","Voice and video calling","Voicemail transcription","Call-to-text","Website chat","Team messaging","Automated workflows","Broadcast messages","Multi-factor authentication","BAA included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Automate$q$, $q$$500/month$q$, $q$monthly$q$, NULL, $q$["Everything in Communicate","Nia AI voice and text assistant","Automatic message routing","Customized workflows","Broadcast voice calling","Appointment scheduling","EHR integration","Early feature access","Premium support","Calling usage billed separately"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Everything in Communicate and Automate","SSO and identity management","Custom onboarding","Dedicated support","Multi-tenant management","Reporting and analytics","API extensions","Volume discounts"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OhMD is a patient communication platform designed specifically for healthcare practices that need to text, call, and message patients while staying HIPAA compliant. Founded in 2015 by Ethan Bechtel in Burlington, Vermont, the company built its reputation on a simple idea: let patients text the same landline number they already call, without requiring either side to install an app.$q$, $q$Today OhMD has grown beyond basic texting into a fuller communication suite that includes voice and video calling, an AI phone assistant, website chat, and EHR-connected automated workflows, aimed at reducing the call volume that overwhelms front-desk staff at small and mid-sized practices.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OhMD's core is two-way SMS and RCS texting tied to a practice's existing landline, paired with voice and video calling, voicemail transcription, and call-to-text conversion so incoming calls can be redirected into a text conversation.$q$, $q$On top of messaging, OhMD adds a website chat widget, internal team messaging, automated patient workflows (reminders, intake forms, recalls), and broadcast messaging for practice-wide announcements. The Automate plan layers in Nia, an AI voice and text assistant that can answer routine calls, handle scheduling questions, and route complex calls to staff, along with EHR integrations for syncing patient records.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0827d2c4-33ac-4c46-a57f-b360cc0f698b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OhMD publishes two named plans on its pricing page: Communicate starting at $300/month for two-way texting, calling, and team messaging, and Automate starting at $500/month for everything in Communicate plus the Nia AI assistant, automatic call/message routing, and EHR integration (calling usage is billed separately).$q$, $q$Larger multi-location organizations can move to a custom-priced Enterprise plan that adds SSO/identity management, dedicated support, multi-tenant management, reporting, and API access, typically with an annual billing commitment and volume discounts.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Single sign-on (SSO)$q$, $q$Provides one-click access across thousands of pre-integrated cloud and on-premise applications through Okta's app catalog.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Adaptive multi-factor authentication$q$, $q$Context-aware MFA adjusts authentication requirements based on device, location, and risk signals.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Universal Directory$q$, $q$Centralizes user, group, and device profiles from multiple sources into a single identity directory.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Lifecycle Management$q$, $q$Automates user provisioning and deprovisioning across connected applications as employment status changes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Identity Governance$q$, $q$Supports access certification, entitlement management, and compliance reporting for regulated industries.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Privileged Access$q$, $q$Secures and audits access to sensitive systems and privileged accounts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Customer Identity Cloud (Auth0)$q$, $q$Developer-focused authentication and authorization APIs for embedding login into customer-facing applications.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$API Access Management$q$, $q$Secures machine-to-machine and API traffic with OAuth 2.0 token issuance and scoped access controls.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Very large catalog of pre-built application integrations for fast SSO rollout$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Vendor-neutral identity platform that works across Microsoft, Google, AWS, and other ecosystems$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Strong developer tooling for customer identity inherited from the Auth0 acquisition$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Mature governance, lifecycle, and privileged access features for regulated enterprises$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Established public company with long operating history and enterprise-grade reliability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Per-user pricing can become expensive at scale for large workforces$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Advanced features like governance and threat protection require higher, custom-priced tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Minimum annual contract value can be a barrier for very small organizations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Two separate product lines (Workforce and Customer Identity) can add complexity when evaluating pricing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Has been the target of high-profile security incidents in past years, drawing scrutiny of its own security practices$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$What does Okta do?$q$, $q$Okta is an identity and access management platform that provides single sign-on, multi-factor authentication, directory services, and lifecycle management for both employee (workforce) and customer-facing applications.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$How much does Okta cost?$q$, $q$Okta Workforce Identity plans start at $6/user/month for the Starter tier, with Core Essentials and Essentials tiers at $14 and $17/user/month respectively; Professional and Enterprise tiers, along with Customer Identity Cloud plans, are custom-priced.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Is Okta the same as Auth0?$q$, $q$No, but they are related. Okta acquired Auth0 in 2021. Auth0 now operates as Okta Customer Identity Cloud, a separate product line focused on developer-facing customer authentication, alongside Okta's original Workforce Identity Cloud.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$When was Okta founded?$q$, $q$Okta was founded in 2009 by Todd McKinnon and Frederic Kerrest and is headquartered in San Francisco, California. It went public in 2017.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$What are the main alternatives to Okta?$q$, $q$Common Okta alternatives include Microsoft Entra ID (Azure AD), Ping Identity, OneLogin, JumpCloud, ForgeRock, and Google Cloud Identity.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Does Okta support multi-factor authentication?$q$, $q$Yes, Okta provides adaptive MFA that adjusts authentication challenges based on contextual risk signals like device, location, and network.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Is there a minimum contract for Okta?$q$, $q$Yes, Okta's Workforce Identity plans typically require a minimum annual contract value, commonly cited around $1,500, in addition to per-user monthly pricing.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Enterprise workforce single sign-on$q$, $q$IT teams centralize employee access to hundreds of internal and SaaS applications behind one login and MFA policy.$q$, $q$IT and security teams at mid-market and enterprise companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Customer-facing app authentication$q$, $q$Developers embed Okta Customer Identity Cloud (Auth0) APIs to handle login, social sign-in, and authorization in consumer or B2B products.$q$, $q$Software engineering and product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Compliance and access governance$q$, $q$Regulated organizations use Identity Governance and Lifecycle Management to automate access certification and provisioning/deprovisioning for audits.$q$, $q$Compliance, security, and IT operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Starter (Workforce Identity)$q$, $q$$6/user/month$q$, $q$annual$q$, NULL, $q$["Single sign-on","Multi-factor authentication","Universal Directory","5 automated workflows"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Core Essentials (Workforce Identity)$q$, $q$$14/user/month$q$, $q$annual$q$, NULL, $q$["Everything in Starter","Adaptive MFA","Privileged Access","Lifecycle Management","Access Governance","50 automated workflows"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Essentials (Workforce Identity)$q$, $q$$17/user/month$q$, $q$annual$q$, NULL, $q$["Same feature set as Core Essentials","Most popular workforce tier"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Professional (Workforce Identity)$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Device Access","Identity Security Posture Management","Identity Threat Protection","Maximum automated workflows"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Enterprise (Workforce Identity)$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Everything in Professional","API Access Management","Access Gateway","Machine-to-machine tokens"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Enterprise Base Platform (Customer Identity)$q$, $q$$3,000/month$q$, $q$annual$q$, NULL, $q$["Unlimited OIDC and SAML apps","Foundational Customer Identity Cloud (Auth0) platform access"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Okta was founded in 2009 by Todd McKinnon and Frederic Kerrest, two former Salesforce executives who saw an opportunity to build cloud-native identity management as enterprises moved away from on-premise directories. Headquartered in San Francisco, the company went public in 2017 and significantly expanded its footprint in 2021 by acquiring Auth0, a leading developer-focused identity platform, for approximately $6.5 billion.$q$, $q$The combined company now operates two product suites: Okta Workforce Identity Cloud, which secures employee access to internal systems, and Okta Customer Identity Cloud (built on Auth0's technology), which lets developers add login, authentication, and authorization to customer-facing apps. Okta serves more than 19,000 customers globally and employs around 6,000 people.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Okta's Workforce Identity Cloud centers on single sign-on across thousands of pre-built application integrations, adaptive multi-factor authentication, and a Universal Directory that centralizes user identities across systems. Lifecycle Management automates provisioning and deprovisioning as employees join, change roles, or leave.$q$, $q$Higher tiers add Privileged Access management, Identity Governance and access certification, Identity Threat Protection, Device Access controls, and API Access Management. Okta Customer Identity Cloud (Auth0) provides developer SDKs, prebuilt login flows, and fine-grained authorization for consumer and B2B applications, including inbound federation for enterprise customers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Workforce Identity is sold per user per month, billed annually, starting with Starter at $6/user/month for core SSO and MFA, moving through Core Essentials ($14/user/month) and Essentials ($17/user/month) for adaptive MFA, lifecycle management, and access governance, up to custom-priced Professional and Enterprise tiers with the fullest feature set. A minimum annual contract applies.$q$, $q$Customer Identity Cloud pricing is structured differently, starting around $3,000/month for an Enterprise Base Platform with unlimited OIDC and SAML applications, with B2C Suite and B2B Suite add-ons priced individually based on monthly active users and required capabilities.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$AI Website Agent$q$, $q$Automatically answers unlimited visitor questions using a business's FAQs and knowledge base, updating itself as content changes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Lead capture and qualification$q$, $q$Identifies and qualifies sales leads from chat conversations before routing them to a human agent.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Proactive engagement$q$, $q$Triggers chat outreach to visitors based on browsing behavior, time on page, or other configurable rules.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Human agent handoff$q$, $q$Seamlessly transfers AI conversations to a live human agent when a visitor's question requires personal attention.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Real-time visitor insights$q$, $q$Shows agents live visitor data, including location and browsing activity, during chat conversations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Reporting and transcripts$q$, $q$Provides chat transcripts, performance reporting, and analytics on conversation volume and outcomes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$CRM and help desk integrations$q$, $q$Connects with tools like Salesforce, HubSpot, Shopify, and Zendesk to sync chat data with existing workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Flat-fee pricing with no overages$q$, $q$Charges a predictable flat monthly fee for AI conversations with no token limits, so traffic spikes do not increase the bill.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Flat-fee pricing avoids the token-based billing surprises common with AI chat competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$AI agent answers unlimited questions with no per-conversation overage charges$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Long operating history since 2009 with a large base of over 11,000 paying customers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Simple setup for small teams that do not want per-resolution or usage-based billing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Free trial available with no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Standard AI plan starts at $400/month, notably more expensive than many basic live chat tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Additional human agent seats add $29/month each on top of the base AI plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Smaller company (roughly 20-35 employees) than large AI chat competitors, which may mean fewer resources for rapid feature development$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Enterprise features like SSO and advanced routing require custom, undisclosed pricing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$AI agent quality depends heavily on how well-maintained a business's FAQ and knowledge base content is$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$What is Olark used for?$q$, $q$Olark is a live chat and AI website agent platform that lets businesses answer visitor questions, capture and qualify leads, and route conversations between AI and human agents on their website.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$How much does Olark cost?$q$, $q$Olark's Standard AI Website Agent plan costs $400/month billed annually and includes one human agent seat, with extra seats at $29/agent/month. A Live Chat Only plan without AI is available for $29/agent/month, and custom Enterprise pricing is available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Does Olark use token-based pricing for its AI agent?$q$, $q$No. Olark uses a flat-fee pricing model with no token limits or usage overages, so a business's bill does not spike during high-traffic periods.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$When was Olark founded?$q$, $q$Olark was founded in 2009 as part of the Y Combinator accelerator by four co-founders working out of a house in Palo Alto, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Can Olark route chats to a human agent?$q$, $q$Yes, the AI Website Agent can hand off conversations to a human agent when a visitor's question needs personal attention.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$What are alternatives to Olark?$q$, $q$Common alternatives include Intercom, Drift, LiveChat, Tidio, and Zendesk Chat.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Is there a free trial for Olark?$q$, $q$Yes, Olark offers a free trial with no credit card required before committing to a paid plan.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$24/7 website lead capture$q$, $q$The AI agent answers visitor questions and qualifies leads outside of business hours, then routes qualified leads to sales.$q$, $q$Small and mid-sized business sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Customer support deflection$q$, $q$Support teams use the AI agent to resolve common questions automatically, reserving human agents for complex issues.$q$, $q$Customer support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$E-commerce visitor engagement$q$, $q$Online stores use proactive chat triggers and live insights to engage shoppers and reduce cart abandonment.$q$, $q$E-commerce and retail businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Standard AI Website Agent$q$, $q$$400/month (billed annually at $4,800/year)$q$, $q$annual$q$, NULL, $q$["Unlimited AI-answered visitor questions","Automatic FAQ and knowledge base updates","Lead capture and qualification","Proactive engagement","One human agent seat included","No token limits or overages","White glove support and account management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Live Chat Only$q$, $q$$29/agent/month$q$, $q$monthly$q$, NULL, $q$["Human-staffed live chat","No AI agent","Available since 2009"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Regional routing and multiple teams","Advanced integrations","Custom workflows and SLAs","Legal reviews and side letters","Single sign-on (SSO)"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Olark was founded in 2009 through Y Combinator by four co-founders operating out of a Palo Alto house, initially as a straightforward live chat widget for websites. Over more than fifteen years the company has grown into a fully remote team serving over 11,000 paying businesses, while staying deliberately small compared to venture-backed rivals like Intercom and Drift.$q$, $q$The product has evolved from pure human-staffed chat into an AI website agent that answers visitor questions around the clock, with the option to fall back to human agents for more complex conversations, all managed from Olark's chat dashboard and mobile apps.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Olark's AI Website Agent answers unlimited visitor questions by drawing on a business's existing FAQs and knowledge base, automatically keeping its answers up to date as content changes. It captures and qualifies leads, proactively engages visitors based on browsing behavior, and routes conversations to human agents when needed.$q$, $q$Beyond the AI layer, Olark provides real-time visitor insights, chat transcripts and reporting, targeted proactive chat triggers, and integrations with CRM, help desk, and e-commerce tools. Enterprise customers can add regional routing across multiple teams, custom workflows, SLAs, and single sign-on.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Olark's primary plan, the Standard AI Website Agent, costs $400/month when billed annually ($4,800/year) and includes the AI agent plus one human agent seat with no token limits or usage-based overages; additional human seats cost $29/agent/month.$q$, $q$Businesses that only need traditional human live chat, without the AI layer, can choose the Live Chat Only plan at $29/agent/month. Larger organizations with complex routing, integration, or compliance needs can request a custom Enterprise plan. A free trial is available with no credit card required.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Node-based compositing$q$, $q$Effects and transitions are built as a graph of connected nodes rather than a fixed stack, offering flexible, modular compositing similar to professional tools.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Cross-platform support$q$, $q$Runs natively on Linux, Windows, and macOS from the same open-source codebase.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Disk caching for smooth playback$q$, $q$Pre-renders portions of the timeline to disk as small images to keep scrubbing and preview playback responsive.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$FFmpeg-based format support$q$, $q$Uses FFmpeg for encoding and decoding, giving broad compatibility with common video and audio formats.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$OpenColorIO color management$q$, $q$Integrates OpenColorIO for consistent, professional-grade color management across a project.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Free and open source$q$, $q$Released under GPLv3 with publicly available source code, free to use, modify, and redistribute.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Completely free with no paid tiers or subscriptions$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Node-based compositing offers more flexible effects workflows than many free editors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Cross-platform on Linux, Windows, and macOS$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Open-source codebase can be inspected, modified, and contributed to by anyone$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Active GitHub community continues to release nightly and pre-release builds$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Officially labeled alpha software and described by developers as highly unstable$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$No commercial support; help comes from community forums and GitHub issues only$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Smaller plugin and template ecosystem compared to commercial editors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Steeper learning curve for users unfamiliar with node-based compositing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Volunteer-driven development pace can be slower and less predictable than funded competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Is Olive Video Editor free?$q$, $q$Yes, Olive Video Editor is completely free and open source under the GNU General Public License version 3, with no paid tiers or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$What platforms does Olive Video Editor support?$q$, $q$Olive runs on Linux, Windows, and macOS from a single open-source codebase.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Is Olive Video Editor stable enough for professional work?$q$, $q$Olive is currently labeled alpha software by its own developers and is described as highly unstable, so it is generally better suited to hobbyist and experimental projects than mission-critical professional work.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$What makes Olive different from other free video editors?$q$, $q$Olive's key differentiator is node-based compositing, which lets users build effects and transitions as a graph of connected nodes for more flexible, modular editing than a fixed effects stack.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Who develops Olive Video Editor?$q$, $q$Olive is developed by the volunteer-run Olive Team, a community of roughly 10-15 contributors, led originally by developer MattKC, who began the project in late 2017.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$What are alternatives to Olive Video Editor?$q$, $q$Popular alternatives include Shotcut, Kdenlive, OpenShot, Blender's Video Sequence Editor, and DaVinci Resolve.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Does Olive Video Editor support 4K and other high-resolution footage?$q$, $q$Olive uses FFmpeg for decoding and encoding, giving it broad format and resolution support, though performance depends on the caching settings and available hardware.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Hobbyist and student video editing$q$, $q$Individuals learning video editing use Olive as a free, no-commitment alternative to paid software.$q$, $q$Students and hobbyist video creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Experimenting with node-based compositing$q$, $q$Editors curious about node-based effects workflows use Olive to learn concepts also found in tools like Nuke or Fusion.$q$, $q$Motion graphics and VFX learners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Open-source contribution and development$q$, $q$Developers contribute code, bug fixes, or translations to the Olive project on GitHub.$q$, $q$Open-source software contributors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$Olive Video Editor$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full node-based compositing editor","Cross-platform Linux, Windows, macOS builds","FFmpeg-based format support","OpenColorIO color management","Open-source GPLv3 license","Community support via GitHub and forums"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Olive Video Editor is a free, open-source, cross-platform non-linear video editor for Linux, Windows, and macOS. Development began in late 2017 under primary maintainer MattKC, with the first public pre-release, version 0.1.0, shipping in May 2019. The project is released under the GNU General Public License version 3 and maintained by the volunteer Olive Team rather than a commercial company.$q$, $q$Olive was created to give creators a free alternative to high-end professional editing software, with a particular focus on node-based effects compositing that was largely missing from other open-source editors at the time.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Olive's defining feature is node-based compositing, which lets users build effects and transitions as a graph of connected nodes instead of a fixed linear effects stack, offering more flexibility and reducing reliance on third-party plugins.$q$, $q$The editor also includes a caching system that pre-renders part or all of a sequence to disk as small preview images, speeding up scrubbing and playback, along with standard non-linear editing tools built on FFmpeg for broad format support and OpenColorIO for color management.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76721f82-dab0-44d8-9e79-1d3b6df99f76', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Olive Video Editor is completely free and open source under the GPLv3 license. There are no paid tiers, subscriptions, or premium feature unlocks; the full application and source code are available at no cost from the project's GitHub repository and website.$q$, $q$Because Olive is community-maintained, users can also build from source or contribute code, translations, and bug reports rather than paying for support, though this also means there is no commercial support contract available.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Predefined shell command execution$q$, $q$Exposes a curated list of shell commands or scripts as clickable actions, avoiding the need to grant full shell access.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$YAML-based configuration$q$, $q$Actions are configured through a simple, human-readable YAML file, making setup and version control straightforward.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Responsive, touch-friendly web UI$q$, $q$The single-page-app interface works well on desktops, tablets, and phones for triggering actions from any device.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Lightweight footprint$q$, $q$Uses only a few megabytes of RAM and minimal CPU, suitable for constrained hardware like a Raspberry Pi.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$No telemetry or internet dependency$q$, $q$Includes no usage tracking, analytics, or ads, and does not require an internet connection to function.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$REST and Connect-RPC API$q$, $q$Exposes a documented API so other tools or dashboards can trigger the same predefined actions programmatically.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Completely free and open source with an active independent developer$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Very lightweight, runs well on low-powered hardware like a Raspberry Pi$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$No telemetry, tracking, ads, or required internet connection$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Simple YAML configuration makes setup approachable for homelab users$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Touch-friendly web UI works well for non-technical household members$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$No commercial support; help relies on community and GitHub issues$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Security researchers have documented OS command injection vulnerabilities (e.g. CVE-2026-27626), requiring careful configuration and updates$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Limited to executing predefined commands, not a general-purpose remote management tool$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Maintained by a single primary developer, which is a bus-factor risk for long-term continuity$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Requires basic comfort with YAML and self-hosting to configure and deploy$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$What is OliveTin used for?$q$, $q$OliveTin is a self-hosted web interface that lets users safely trigger a predefined list of shell commands or scripts from a web dashboard, without granting full shell or SSH access.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Is OliveTin free?$q$, $q$Yes, OliveTin is free and open source under the AGPL-3.0 license, with no paid tier or subscription.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Who created OliveTin?$q$, $q$OliveTin was created by developer James Read, who introduced the project publicly in mid-2021.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$What programming language is OliveTin written in?$q$, $q$OliveTin's backend is written in Go, with a web-based single-page-app frontend using a REST and Connect-RPC API.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Is OliveTin secure?$q$, $q$OliveTin is designed to limit users to predefined commands, but like any tool that executes shell commands, it should be run behind authentication and kept updated; a 2026 CVE documented command injection issues in its shell execution mode.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Can OliveTin run on a Raspberry Pi?$q$, $q$Yes, OliveTin uses only a few megabytes of RAM and minimal CPU, making it well suited to low-powered devices like a Raspberry Pi.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Does OliveTin require an internet connection?$q$, $q$No, OliveTin does not require an internet connection for any of its functionality and includes no telemetry or tracking.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Homelab server management$q$, $q$Self-hosters expose common maintenance commands, like restarting Docker containers or rebooting devices, as safe web buttons.$q$, $q$Homelab and self-hosting enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Non-technical household access$q$, $q$Family members can trigger pre-approved actions, like restarting a media server, without needing terminal access.$q$, $q$Household users of a shared home server$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$Constrained-hardware automation$q$, $q$Runs alongside other self-hosted apps on low-powered devices like a Raspberry Pi to trigger scripts and backups.$q$, $q$Sysadmins running lightweight home servers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$OliveTin$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Predefined shell command execution","YAML configuration","Responsive web UI","REST and Connect-RPC API","No telemetry or tracking","Self-hosted via Docker or .deb package"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OliveTin is a free, open-source, self-hosted web interface that exposes a curated list of predefined shell commands as clickable buttons, rather than giving users full shell or SSH access. It was created by developer James Read and first introduced publicly in mid-2021, and has since become a popular homelab and self-hosting tool.$q$, $q$The project is written in Go, uses a gRPC/Connect-RPC API, and ships a responsive single-page-app frontend, all released under the AGPL-3.0 open-source license with no company or commercial offering behind it.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Administrators define available actions in a simple YAML configuration file, mapping each action to a shell command or script; OliveTin then renders these as buttons on a web dashboard that any authorized user can click to trigger the underlying command.$q$, $q$The interface is touch-friendly and works well on phones and tablets, uses only a few megabytes of RAM, includes no telemetry, tracking, or ads, and requires no internet connection to operate, making it well suited to constrained, self-hosted hardware like a Raspberry Pi.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('245c9bbd-59a4-47bd-b20c-befa7fb09e7b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OliveTin is completely free and open source under the AGPL-3.0 license. There is no paid version, subscription, or commercial tier; users self-host it on their own hardware, typically via a .deb package or Docker container.$q$, $q$Because there is no company behind the project, support is provided through the open-source community, GitHub issues, and the developer's own blog and social channels rather than a paid support contract.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Local LLM inference$q$, $q$Runs large language models entirely on a user's own hardware, with no data sent to a third-party API by default.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Simple CLI and REST API$q$, $q$Pull, run, and manage models with single commands or integrate Ollama into applications via its REST API.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Broad model library$q$, $q$Provides one-command access to popular open-weight models including Llama, Qwen, Gemma, Phi, DeepSeek, Mistral, and gpt-oss.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Cross-platform support$q$, $q$Runs natively on macOS, Windows, and Linux, plus an official Docker image for containerized deployments.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$GPU and CPU acceleration$q$, $q$Supports NVIDIA CUDA, Apple Silicon Metal, and AMD ROCm acceleration, with automatic CPU fallback when no GPU is available.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Automatic model management$q$, $q$Handles model downloading, quantization, and memory allocation automatically, abstracting away llama.cpp's complexity.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Ollama Cloud$q$, $q$Optional paid cloud tiers offload inference to Ollama's infrastructure for larger models or higher concurrency than local hardware supports.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Community integrations$q$, $q$Supports more than 67,000 community-built integrations connecting Ollama to other developer tools and applications.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Core local runtime is completely free and open source with no per-token cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Runs entirely offline, keeping data on the user's own device for privacy-sensitive use cases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Broad model library with one-command installation of popular open-weight models$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Cross-platform support across macOS, Windows, Linux, and Docker$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Large, active developer community with tens of thousands of integrations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Local model performance is limited by the user's own hardware, especially without a capable GPU$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Cloud tier pricing (Pro at $20/month, Max at $100/month) adds cost for users needing more concurrency or larger models$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$AMD GPU acceleration is Linux-only as of 2026, limiting Windows AMD users to CPU inference$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Managing local models and disk space can become cumbersome as model libraries grow$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$As a young, fast-growing company (founded 2023), product and pricing details are still evolving$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Is Ollama free?$q$, $q$Yes, Ollama's local runtime is free forever and open source under the MIT license, with unlimited use on your own hardware. An optional paid Ollama Cloud tier exists for offloading heavier workloads.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$What models can I run with Ollama?$q$, $q$Ollama supports a wide range of open-weight models including Llama, Qwen, Gemma, Phi, DeepSeek, Mistral, and gpt-oss, downloadable from the Ollama model library with a single command.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Does Ollama require a GPU?$q$, $q$No, Ollama can run on CPU alone via llama.cpp's GGUF kernels, though a GPU (NVIDIA CUDA, Apple Silicon Metal, or AMD ROCm on Linux) significantly improves performance for larger models.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$What is Ollama Cloud?$q$, $q$Ollama Cloud is a paid service for offloading inference to Ollama's infrastructure when local hardware is insufficient, with Free, Pro ($20/month), and Max ($100/month) tiers offering increasing concurrency and usage.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Who founded Ollama?$q$, $q$Ollama was founded in 2023 by Jeffrey Morgan and Michael Chiang, both Y Combinator alumni, and is based in Palo Alto, California.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Does Ollama send my data to the cloud?$q$, $q$When running models locally, no data leaves your device. For Ollama Cloud usage, the company states that prompt and response data is never logged or used for training.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$What are alternatives to Ollama?$q$, $q$Common alternatives for running LLMs locally include LM Studio, GPT4All, Jan, and using llama.cpp directly, while cloud-hosted inference alternatives include Groq, Together AI, and Replicate.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Private, offline AI development$q$, $q$Developers run models locally to prototype AI features without sending data to third-party APIs.$q$, $q$Software developers and AI engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Privacy-sensitive enterprise deployment$q$, $q$Organizations with strict data handling requirements run LLMs on internal infrastructure using Ollama instead of external APIs.$q$, $q$Enterprises with compliance or data residency requirements$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$AI experimentation and learning$q$, $q$Hobbyists and students experiment with different open-weight models on personal hardware to learn about LLM behavior.$q$, $q$AI hobbyists, students, and researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Local (self-hosted)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Unlimited local model inference","Access to full Ollama model library","CLI and REST API","Cross-platform support","Open-source MIT license"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Ollama Cloud Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["1 concurrent model","Access to Ollama Cloud infrastructure","No data logging or training on prompts"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Ollama Cloud Pro$q$, $q$$20/month ($200/year)$q$, $q$monthly or annual$q$, NULL, $q$["3 concurrent models","Roughly 50x more cloud usage than Free tier"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$Ollama Cloud Max$q$, $q$$100/month$q$, $q$monthly$q$, NULL, $q$["10 concurrent models","Roughly 5x more usage than Pro tier"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ollama is an open-source platform that lets developers and enthusiasts download, manage, and run open-weight large language models directly on their own computers. Founded in 2023 by Jeffrey Morgan and Michael Chiang, both Y Combinator alumni, the company is based in Palo Alto, California, and has raised approximately $88 million through a Series B round completed in July 2026.$q$, $q$The project has grown rapidly, reporting 8.9 million monthly active developers and more than 67,000 community-built integrations, with partnerships across major model labs and hardware vendors. Its core product remains free and open source, with a newer paid cloud tier for users who need more compute than their local hardware provides.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Ollama wraps the llama.cpp inference engine behind a simple command-line interface and REST API, letting users pull and run models like Llama, Qwen, Gemma, Phi, DeepSeek, Mistral, and gpt-oss with a single command, without manually managing quantization or GPU memory allocation.$q$, $q$It runs on macOS, Windows, Linux, and Docker, with GPU acceleration support for NVIDIA CUDA, Apple Silicon Metal, and AMD ROCm (Linux only), plus an automatic CPU fallback path so models can run on machines without a dedicated GPU.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c830bb2b-1cd7-47d7-b6a1-c48147945ecf', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Ollama's local runtime is free forever under an open-source license, with unlimited use on a user's own hardware and no usage-based fees for local inference.$q$, $q$For workloads beyond local hardware capacity, Ollama Cloud offers a Free tier ($0, 1 concurrent model), a Pro tier ($20/month or $200/year, 3 concurrent models and roughly 50x the cloud usage of Free), and a Max tier ($100/month, 10 concurrent models and roughly 5x the usage of Pro).$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Movie, TV, and music requests$q$, $q$Lets users request entire movies, TV series, specific seasons or episodes, and music albums from a browsable catalog.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Sonarr, Radarr, and Lidarr integration$q$, $q$Automatically forwards approved requests to Sonarr, Radarr, or Lidarr (and legacy CouchPotato/SickRage) to handle acquisition.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Approval workflows$q$, $q$Administrators can require approval for requests or whitelist trusted users for automatic approval.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Multi-account support$q$, $q$Supports Plex.tv, Emby, and local user accounts, with user management for shared media servers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Duplicate detection$q$, $q$Checks whether requested content already exists on the connected media server before forwarding a new request.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Notifications$q$, $q$Sends configurable notifications through multiple channels to keep requesters updated on request status.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Cross-platform deployment$q$, $q$Runs on Windows, macOS, Linux, and Docker, fitting easily into existing self-hosted media server setups.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Completely free and open source with no subscription cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Deep integration with the popular Sonarr, Radarr, and Lidarr media automation stack$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Supports Plex, Emby, and Jellyfin, covering the most common self-hosted media servers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Flexible approval workflow lets admins balance automation with control$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Long track record dating back to its 2016-2017 origins as PlexRequests.Net$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$No commercial support; relies on community forums and GitHub issues$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Interface and development pace have been seen by some users as less modern than newer alternatives like Overseerr or Jellyseerr$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Requires a self-hosted server and some technical setup, including API keys for each connected media automation service$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$No official cloud-hosted or managed version$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Maintained by a smaller open-source community than some newer forks in the space$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Is Ombi free?$q$, $q$Yes, Ombi is free and open source under the GPLv3 license, with no paid tier or subscription.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$What media servers does Ombi support?$q$, $q$Ombi supports Plex, Emby, and Jellyfin media servers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$How does Ombi work with Sonarr and Radarr?$q$, $q$When a user requests a movie or TV show, Ombi checks whether it already exists on the media server and, if not, automatically forwards the request to Radarr (movies) or Sonarr (TV shows) to handle downloading and adding the content.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$What was Ombi called before?$q$, $q$Ombi began as PlexRequests.Net, created by developer tidusjar, and was renamed Ombi around January 2017 as it expanded beyond Plex-only support.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Can I control who can request content in Ombi?$q$, $q$Yes, administrators can require manual approval for requests or whitelist trusted users so their requests are automatically approved.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Does Ombi run in Docker?$q$, $q$Yes, Ombi is commonly deployed via Docker, alongside Windows, macOS, and Linux installation options.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$What are alternatives to Ombi?$q$, $q$The most common alternatives are Overseerr and its actively maintained fork Jellyseerr, along with older tools like Petio.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Shared home media server requests$q$, $q$Family members or friends with access to a Plex, Emby, or Jellyfin server submit requests for new movies or shows without needing admin access.$q$, $q$Homelab operators sharing a media server$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Automated media library growth$q$, $q$Approved requests automatically flow into Sonarr, Radarr, or Lidarr to be downloaded and added to the library.$q$, $q$Self-hosted media automation enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Controlled content approval$q$, $q$Server admins use approval workflows to review and moderate what content gets added, balancing automation with oversight.$q$, $q$Media server administrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$Ombi$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Movie, TV, and music requests","Sonarr, Radarr, Lidarr integration","Approval workflows","Plex, Emby, Jellyfin support","Multi-account management","Notifications","Cross-platform, Docker-ready"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ombi is a free, open-source, self-hosted web application that lets people request movies, TV shows, and music for a Plex, Emby, or Jellyfin media server. It began as PlexRequests.Net, created by developer tidusjar, and was renamed Ombi around January 2017 as support expanded beyond Plex to Emby and later Jellyfin.$q$, $q$The project is released under the GPLv3 license and maintained by open-source contributors on GitHub rather than a commercial company. It has become a standard part of many self-hosted media automation setups, sitting alongside tools like Sonarr, Radarr, and Lidarr.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users browse a searchable catalog and submit requests for movies, TV shows (whole series, specific seasons, or single episodes), or music. Ombi checks whether the content already exists on the connected media server and, if not, automatically forwards the request to Radarr, Sonarr, or Lidarr to handle acquisition.$q$, $q$Administrators can enable an approval workflow, whitelist trusted users for automatic approval, manage accounts across Plex.tv, Emby, and local logins, and configure notifications across multiple channels so requesters stay informed about the status of their requests.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ffe78cc3-84d8-4e34-88df-15226b1e5736', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Ombi is completely free and open source under the GPLv3 license. There is no paid tier, subscription, or commercial edition; users self-host it on their own hardware or a home server, typically alongside their Plex, Emby, or Jellyfin installation.$q$, $q$Because there is no company behind Ombi, support is community-driven through GitHub issues, forums, and self-hosting communities rather than a paid support contract.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Dublin Core metadata cataloging$q$, $q$Items are cataloged using the Dublin Core standard by default, with customizable item types and fields for specialized collections.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Exhibit Builder$q$, $q$Lets curators assemble collection items into narrative, multi-page online exhibits without coding.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Plugin ecosystem$q$, $q$Extends core functionality with community and RRCHNM-built plugins for mapping, geolocation, PDF embedding, and more.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Theme customization$q$, $q$Offers switchable themes to customize the public-facing design of a collection or exhibit site.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Standards-based metadata export$q$, $q$Supports standards-based metadata that make collections interoperable with library and archive systems.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Self-hosted single-site architecture$q$, $q$Runs as a self-hosted PHP/MySQL application focused on a single collection or exhibit site per installation.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Completely free and open source to download and self-host$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Purpose-built for cultural heritage metadata standards like Dublin Core$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Simple, blogging-software-like administrative interface lowers the barrier for non-technical curators$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Exhibit Builder makes it easy to turn a collection into a narrative online exhibit$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Long track record and active community since its 2008 release, backed by an academic center$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Requires users to supply and maintain their own PHP/MySQL web server for self-hosting$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Single-site architecture limits institutions that need to manage many related sites from one installation (Omeka S is better suited for that)$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Plugin and theme ecosystem is smaller than general-purpose CMS platforms like WordPress$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Managed hosting via Omeka.net requires a separate paid subscription for those who do not want to self-host$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Development pace is slower than commercially-backed CMS platforms since it is maintained by an academic center$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Is Omeka Classic free?$q$, $q$Yes, Omeka Classic is free and open-source software that can be downloaded and self-hosted at no cost, though you need your own PHP/MySQL web server.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Who created Omeka?$q$, $q$Omeka was developed starting in 2007 by the Center for History and New Media (now the Roy Rosenzweig Center for History and New Media) at George Mason University, with its first public release in February 2008.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$What is the difference between Omeka Classic and Omeka S?$q$, $q$Omeka Classic is a single-site content management system for one collection or exhibit, while Omeka S is a separate, newer product from the same team that supports multiple sites, an API-first architecture, and Linked Open Data from a single installation.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$What is Omeka.net?$q$, $q$Omeka.net is a separate, paid managed hosting service from RRCHNM that runs Omeka Classic without requiring users to install or maintain their own server, with annual plans ranging from free to $1,000/year.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$What metadata standard does Omeka Classic use?$q$, $q$Omeka Classic uses the Dublin Core metadata standard by default, with customizable item types for specialized cataloging needs.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Who uses Omeka Classic?$q$, $q$Omeka Classic is primarily used by museums, libraries, archives, historical societies, and individual scholars to publish digital collections and online exhibits.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Can I build online exhibits with Omeka Classic?$q$, $q$Yes, Omeka Classic includes an Exhibit Builder that lets curators arrange collection items into narrative, multi-page online exhibits without writing code.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Digital library and archive collections$q$, $q$Libraries and archives catalog and publish digitized collections online using Dublin Core metadata standards.$q$, $q$Academic and public libraries, archives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Museum and historical society exhibits$q$, $q$Institutions build narrative online exhibits from their collections using the Exhibit Builder.$q$, $q$Museums and historical societies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Academic research and course projects$q$, $q$Scholars and students publish focused digital collections for research projects or class assignments.$q$, $q$University faculty, researchers, and students$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Omeka Classic (self-hosted)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full open-source CMS software","Dublin Core metadata cataloging","Exhibit Builder","Plugin and theme ecosystem","Requires self-hosted PHP/MySQL server"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Omeka.net Free$q$, $q$Free$q$, $q$annual$q$, NULL, $q$["Single hosted site","Limited themes and plugins","Managed hosting by RRCHNM"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Omeka.net Plus$q$, $q$$35/year$q$, $q$annual$q$, NULL, $q$["Increased storage","Additional themes and plugins"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Omeka.net Silver$q$, $q$$75/year$q$, $q$annual$q$, NULL, $q$["More storage","Expanded plugin and theme access"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Omeka.net Gold$q$, $q$$350/year$q$, $q$annual$q$, NULL, $q$["Higher storage tier","Broader plugin and theme access","Support for more sites"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$Omeka.net Platinum$q$, $q$$1,000/year$q$, $q$annual$q$, NULL, $q$["Maximum storage tier","Full plugin and theme access","Support for the most sites"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Omeka Classic is a free, open-source content management system built specifically for publishing digital collections and online exhibits. Development began in 2007 at the Center for History and New Media at George Mason University (renamed the Roy Rosenzweig Center for History and New Media, or RRCHNM, in 2011), with the first public release in February 2008.$q$, $q$The platform was created to give museums, libraries, and archives a free, standards-based way to publish collections online with an administrative interface as simple as blogging software, at a time when few affordable alternatives existed for cultural heritage institutions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Omeka Classic catalogs items using the Dublin Core metadata standard by default, with customizable item types and unlimited metadata fields to fit different collection needs. Its Exhibit Builder lets curators arrange items into narrative, multi-page online exhibits without writing code.$q$, $q$A plugin and theme ecosystem extends core functionality with features like geolocation and mapping, PDF and document embedding, and custom site design, while its single-site architecture keeps setup and administration relatively simple compared to multi-site platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b2e566c-aa95-4d92-9240-49088a68d179', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Omeka Classic itself is completely free and open source; the software can be downloaded and self-hosted at no cost, provided the user supplies a compatible PHP/MySQL web server.$q$, $q$For institutions that do not want to self-host, RRCHNM offers a separate managed hosting service, Omeka.net, with annual plans including a free tier and paid tiers such as Plus ($35/year), Silver ($75/year), Gold ($350/year), and Platinum ($1,000/year), which scale by storage, number of sites, and available themes and plugins.$q$]::text[], 2);
