-- ── OhMD ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OhMD is a HIPAA-compliant patient communication platform that lets medical practices text, call, and message patients from their existing landline, with an AI assistant to automate routine calls.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$300/month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Burlington, Vermont, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OhMD Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OhMD review 2026: HIPAA-compliant patient texting and AI call automation for medical practices. See pricing, features, pros, cons and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OhMD is a HIPAA-compliant patient communication and engagement platform built for medical, dental, and specialty healthcare practices. It was co-founded in 2015 by CEO Ethan Bechtel in Burlington, Vermont, after his own experience with repeated orthopedic injuries exposed how inefficient phone-based patient communication was. OhMD's core product lets practices text-enable their existing office landline so patients can send and receive secure two-way SMS and RCS messages without either party downloading an app. The platform bundles voice and video calling, voicemail transcription, call-to-text conversion, a website chat widget, internal team messaging, automated workflows, and broadcast messaging into a single inbox, all covered by a signed Business Associate Agreement (BAA) and multi-factor authentication to satisfy HIPAA requirements. Its key differentiator versus generic business texting tools (like Podium or Weave) is a purpose-built healthcare focus: EHR integrations, patient-specific automated workflows (appointment reminders, intake, recalls), and an AI voice and text assistant called Nia that answers routine phone calls, books openings on the calendar, and routes complex calls to staff, directly targeting the high call volume that burdens front-desk teams. OhMD sells three tiers: Communicate ($300/month) for practices that primarily need HIPAA-compliant texting and calling; Automate ($500/month) which adds the Nia AI assistant, automatic message routing, and EHR integration, with calling usage billed separately; and a custom-priced Enterprise tier for multi-location health systems needing SSO, dedicated support, and API access. OhMD is a small, privately held company (roughly 40-50 employees) that has historically positioned itself as a free-to-use texting layer for eliminating 'phone tag,' later evolving into a paid, AI-augmented communication suite. Target customers are small to mid-sized outpatient practices, dental offices, and physical therapy or specialty clinics that get most patient contact by phone and want to cut hold times and no-shows. Primary competitors and alternatives include Klara, Weave, Podium, Solutionreach, and Luma Health, most of which compete on similar two-way texting plus AI receptionist positioning for healthcare and dental verticals.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0827d2c4-33ac-4c46-a57f-b360cc0f698b';

