-- ── olivetin ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OliveTin is a free, self-hosted web interface, written in Go, that gives safe and simple access to predefined shell commands, popular with homelab and self-hosting users.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Independent open-source project$q$, company_size),
  headquarters = COALESCE($q$Distributed open-source project (no formal headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OliveTin Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OliveTin review 2026: self-hosted web UI for running predefined shell commands safely. Features, setup, pros, cons, and alternatives for homelab users.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OliveTin is a free, open-source, self-hosted web application that gives safe and simple access to predefined shell commands from a web interface, without exposing a full terminal or SSH access. It was created by developer James Read, who introduced the project publicly in mid-2021, making it roughly five years old as of 2026. OliveTin is written in Go for its backend, uses gRPC/Connect-RPC for its API, and ships a modern single-page-app web frontend that is responsive and touch-friendly, making it usable from phones and tablets as well as desktops. The project is released under the GNU Affero General Public License version 3 (AGPL-3.0) and is entirely free, with no paid tier, company, or commercial entity behind it; it is maintained as an independent open-source project on GitHub under the OliveTin organization. Its core use case is letting a homelab operator or sysadmin define a fixed list of shell commands or scripts in a simple YAML configuration file (for example, restarting a Docker container, rebooting a Raspberry Pi, or triggering a backup script), which then appear as clickable buttons on a lightweight web dashboard. This lets non-technical household members, or less-trusted users, safely trigger specific pre-approved actions without ever having shell or SSH access to the underlying server. OliveTin explicitly avoids telemetry, analytics, tracking, and ads, and does not require any internet connection to function, positioning it firmly as a privacy-respecting, self-hosted tool for the home server and homelab community. It uses only a few megabytes of RAM and minimal CPU, so it can run happily on constrained hardware like a Raspberry Pi alongside other self-hosted services such as Ombi, Sonarr, or Home Assistant. Because access control is central to its safety model, OliveTin has also been the subject of security research; a 2026 CVE (CVE-2026-27626) documented OS command injection vectors in its Shell-mode execution path, underscoring the importance of running it behind proper authentication and keeping it updated. There is no commercial competitor in the traditional sense; the closest alternatives are general-purpose tools like Cockpit, Webmin, Ansible Semaphore, or custom cron/webhook scripts that homelab users might otherwise cobble together.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '245c9bbd-59a4-47bd-b20c-befa7fb09e7b';

