  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Ombi Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Ombi review 2026: free self-hosted media request tool for Plex, Emby, and Jellyfin. Features, Sonarr/Radarr integration, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Ombi is a free, open-source, self-hosted media request, user management, and discovery web application for Plex, Emby, and Jellyfin media server owners. The project began life as PlexRequests.Net, created by developer tidusjar, and was renamed to Ombi around January 2017 as its scope expanded beyond Plex-only requests to also support Emby and later Jellyfin. It is released under the GNU General Public License version 3 (GPLv3) and maintained on GitHub under the Ombi-app organization by a community of open-source contributors rather than a commercial company, so it has no headquarters, employee count, or funding. Ombi's core function is letting end users, typically family members or friends with access to a shared media server, browse a catalog and request movies, TV shows, or music without needing direct access to server management tools. When a request comes in, Ombi checks whether the content already exists on the connected media server, and if not, automatically forwards the request to the appropriate companion tool in the self-hosted media automation ecosystem: Radarr for movies, Sonarr for TV shows, and Lidarr (or legacy tools like CouchPotato and SickRage) for music, which then handle downloading and adding the content. Administrators can configure an approval workflow, automatically approve trusted users, manage user accounts (including native Plex.tv, Emby, and local accounts), and send notifications through various channels to keep requesters updated on request status. Ombi runs cross-platform via Windows, macOS, Linux, and Docker, making it a standard component of self-hosted media automation setups alongside Sonarr, Radarr, Prowlarr, and the media servers themselves. Because it is entirely free and open source, there is no pricing tier or subscription; the closest thing to a paid dimension is the underlying compute and storage costs of the self-hosted server it runs on. Ombi's primary audience is homelab operators and small groups who run private media servers and want a polished, self-service way for other users to request new content without giving them admin access. Its main open-source alternatives are Overseerr and its actively maintained fork Jellyseerr, which have become popular for their more modern interface and, notably, appear to have overtaken Ombi in community mindshare in recent years, alongside older tools like Petio.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ffe78cc3-84d8-4e34-88df-15226b1e5736';

