-- ── omeka ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Omeka Classic is a free, open-source content management system for building single-site digital collections and narrative exhibits, built by George Mason University's Roy Rosenzweig Center for History and New Media.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$Academic center team (RRCHNM)$q$, company_size),
  headquarters = COALESCE($q$Fairfax, Virginia, United States (George Mason University)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$and other community-translated locales$q$]::text[],
  seo_title = COALESCE($q$Omeka Classic Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Omeka Classic review 2026: free open-source CMS for digital collections and exhibits from George Mason University. Features, hosting options, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Omeka Classic (omeka.org) is a free, open-source web publishing platform purpose-built for museums, libraries, archives, and scholars to publish digital collections and narrative online exhibits. Development began in 2007 within the Center for History and New Media (renamed the Roy Rosenzweig Center for History and New Media, or RRCHNM, in 2011) at George Mason University, and the software was first released publicly in February 2008. It was created because few affordable options existed at the time for cultural heritage institutions to publish standards-based, metadata-rich collections to the web with a blogging-software-simple administrative interface. Omeka Classic uses the Dublin Core metadata standard by default, supports item-level cataloging with unlimited fields via customizable item types, and offers a plugin and theme ecosystem for extending functionality (exhibit building, mapping, geolocation, PDF embedding, and more). As a self-hosted, single-site CMS, Omeka Classic is entirely free to download and install under an open-source license, though users must supply and maintain their own web server meeting its PHP/MySQL requirements. RRCHNM also operates a separate managed hosting service, Omeka.net, and offers paid managed hosting for Omeka Classic installs, with Omeka.net's annual hosted plans ranging from a free tier up to Plus ($35/year), Silver ($75/year), Gold ($350/year), and Platinum ($1,000/year), which vary by storage, number of sites, and available themes and plugins; these hosted plans are a separate product from the free, self-hosted Omeka Classic software itself. Omeka Classic has a sibling product, Omeka S, also from RRCHNM, which is a newer, multi-site, API-first, Linked Open Data-oriented platform for institutions managing multiple related sites from one installation; Omeka S is a separate downloadable product and listed separately, while this entry covers Omeka Classic specifically. Omeka Classic's target audience is academic libraries, museums, historical societies, and individual scholars building focused, single-site digital collections or exhibits, often for a course, research project, or small institutional archive. Its closest alternatives include Omeka S (for multi-site or API-driven needs), CONTENTdm, CollectiveAccess, and general-purpose CMS platforms like WordPress or Drupal when adapted for digital collections work, though none match Omeka Classic's purpose-built focus on standards-based cultural heritage metadata and exhibit-building.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5b2e566c-aa95-4d92-9240-49088a68d179';

